noncompliant:
// Noncompliant: #ifndef without matching #define
#ifndef MYHEADER_H
// Missing #define MYHEADER_H

struct MyStruct {
    int value;
};

void myFunction();

#endif

compliant:
// Compliant: Proper header guard with matching #define
#ifndef MYHEADER_H
#define MYHEADER_H

struct MyStruct {
    int value;
};

void myFunction();

#endif
